	// Format: "### Role: persona-name" - must be at start of line
	personaPattern := regexp.MustCompile(`(?m)^###\s+([^:]+):\s+([^\n]+)`)
	matches := personaPattern.FindAllStringSubmatch(personasSection, -1)

